import '../../../protocol/navivox_voice_run.dart';
import 'gateway_voice_run_policy.dart';

void main() {
  submittedVoiceRunDoesNotCarryStaleFailureReason();
  submittedVoiceRunUsesCurrentNullableSession();
}

void submittedVoiceRunDoesNotCarryStaleFailureReason() {
  final failedRun = _pendingRun().markFailed('Gateway is not connected.');

  final submitted = navivoxGatewaySubmittedVoiceRun(
    run: failedRun,
    requestId: 'request-2',
    sessionId: 'session-2',
  );

  _expect(
    submitted.status == NavivoxVoiceRunStatus.submitted,
    'run should be submitted after retry policy transition',
  );
  _expect(
    submitted.reason == null,
    'submitted retry should not keep a stale terminal failure reason',
  );
}

void submittedVoiceRunUsesCurrentNullableSession() {
  final submittedRun = _pendingRun().markSubmitted(
    requestId: 'request-1',
    sessionId: 'session-1',
  );

  final resubmitted = navivoxGatewaySubmittedVoiceRun(
    run: submittedRun,
    requestId: 'request-2',
    sessionId: null,
  );

  _expect(
    resubmitted.requestId == 'request-2',
    'resubmission should replace the request id',
  );
  _expect(
    resubmitted.sessionId == null,
    'resubmission should reflect the current absent session id',
  );
}

